let lastTime = 0;
let speedHack = false;

function update(delta) {
    if (speedHack) return;

    let currentTime = performance.now();
    let timeElapsed = currentTime - lastTime;
    lastTime = currentTime;

    // Update player position based on delta time
    player.x += player.speed * Math.cos(player.angle) * timeElapsed / 1000;
    player.y += player.speed * Math.sin(player.angle) * timeElapsed / 1000;

    // Calculate distance traveled
    let distanceTraveled = Math.sqrt(Math.pow(player.x - lastPlayerX, 2) + Math.pow(player.y - lastPlayerY, 2));

    // Update UI with new position and distance
    document.getElementById("player-position").textContent = `x: ${player.x.toFixed(2)}, y: ${player.y.toFixed(2)}`;
    document.getElementById("distance-traveled").textContent = `${distanceTraveled.toFixed(2)} units`;

    lastPlayerX = player.x;
    lastPlayerY = player.y;

    // Call update function again after a short delay
    setTimeout(update, 16); // 60 FPS
}

function checkSpeedHack() {
    let currentTime = performance.now();
    if (currentTime - lastTime < 1000 / 120) { // 8.33 ms = 120 FPS
        speedHack = true;
    } else {
        speedHack = false;
    }
}

setInterval(() => {
    let now = performance.now();
    let delta = now - lastTime;
    lastTime = now;

    checkSpeedHack();

    update(delta);
}, 16); // 60 FPS

// Initialize player position and UI
